// Slow organic colour wash, breathes in brightness.
h = perlin1D(i*0.05 + t*0.1)*0.4 + 0.5;
b = wave(time(6));
hsv(h, 1, b*0.9 + 0.1);

// Hot core, cooler tips, animated with perlin.
y = i/n;
flame = perlin2D(y*3, t*1.4);
h = 0.05 - flame*0.05;
v = clamp(flame*1.5 - y*0.4, 0, 1);
hsv(h, 1, v);

x = i/n;
swell = perlin2D(x*2, t*0.4);
h = 0.5 + swell*0.1;
s = 1 - swell*0.3;
v = wave(x + t*0.1);
hsv(h, s, v);

// Bright head, decaying tail.
head = time(4)*n;
d = abs(i - head);
d = min(d, abs(i - head - n));
v = clamp(1 - d/8, 0, 1);
v = v*v;
hsv(0.6, 0.4, v);

// Knight-Rider sweep with falloff.
pos = (triangle(time(3)))*n;
d = abs(i - pos);
v = clamp(1 - d/4, 0, 1);
hsv(0, 1, v*v);

// Twinkling stars, hash for stable per-pixel phase.
phase = hash(i)*10;
blink = wave(t*1.5 + phase);
blink = pow(blink, 6);
hsv(0.6, 0.2, blink);

x = i/n;
p = perlin2D(x*4 + t*0.3, t*0.2);
h = p + time(20);
hsv(h, 1, 1);

// Hard-edged moving bars with adjustable duty.
bar = square(i*0.1 + time(2), 0.4);
hsv(time(15), 1, bar);

x = i/n;
b = triangle(x*3 + time(4));
hsv(x + time(10), 1, b);

x = i/n;
blob = perlin2D(x*2.5, t*0.5);
blob = smoothstep(0.45, 0.6, blob);
h = mix(0.02, 0.12, blob);
hsv(h, 1, blob*0.9 + 0.1);

// Two-beat heartbeat envelope.
p = frac(time(1.2));
beat = pow(wave(p*2), 8) + pow(wave(p*2 + 0.3), 8)*0.7;
hsv(0, 1, clamp(beat, 0, 1));

pos = triangle(time(5))*n;
d = abs(i - pos);
v = clamp(1 - d/6, 0, 1);
hsv(i/n + time(8), 1, v);

// Random forest of greens, occasional warm flicker.
phase = hash(i)*7;
brt = pow(wave(t*0.8 + phase), 4);
h = 0.33 + hash(i+1)*0.06;
if (hash(i+5) > 0.92) h = 0.07;
hsv(h, 0.9, brt);

// Four colour stripes, slow drift.
stripe = floor(frac(i/n + time(8))*4);
hsv(stripe*0.25, 1, 1);

pos = triangle(time(2))*(n-1);
v = i==floor(pos+0.5) ? 1 : 0;
hsv(0.83, 1, v);

// Slow drifting hue painted by 2D noise.
h = perlin2D(i*0.04, t*0.15);
s = 0.6 + perlin1D(i*0.1 + 100)*0.4;
hsv(h, s, 1);

// Hard strobe at ~5 Hz, hue drifts.
flash = square(time(0.2), 0.15);
hsv(time(6), 1, flash);

// Smooth pendulum sweep using sine.
s = wave(time(3));
pos = s*(n-1);
d = abs(i - pos);
v = clamp(1 - d/3, 0, 1);
hsv(0.55, 1, v*v);

// Deep blues and purples with bright stars.
star = pow(wave(t*0.7 + hash(i)*9), 8);
dust = perlin2D(i*0.1, t*0.2)*0.3;
h = 0.72 + dust*0.1;
v = star + dust*0.4;
hsv(h, 1 - star*0.3, v);

// Bass=red, mids=green, highs=purple. Strip is divided
// into 8 bands; each pixel's hue = its band index → hue
// (mapped 0..0.83 so the high end lands on magenta/purple).
b = floor(i / n * 8);
lev = band(b);
hsv(b/8 * 0.83, 1, lev);

// Each pixel maps to a band, lights up if level > threshold.
b = floor(i / n * 8);
thresh = (i/n - floor(i/n*8)/8) * 8;
lev = band(b);
h = b/8 * 0.83;
on = lev > thresh ? 1 : 0;
hsv(h, 1, on * lev);

// Pixels light up to the current VU level.
// Green low, yellow mid, red top.
level = vu();
x = i/n;
lit = x < level ? 1 : 0;
h = (1 - x) * 0.33;
hsv(h, 1, lit);

// Whole strip flashes on each beat.
b = beat();
hsv(time(20), 1, b);

// Bass drives brightness, ambient drift drives hue.
h = perlin1D(i*0.05 + t*0.2);
v = bass()*1.3 + 0.05;
hsv(h, 1, clamp(v, 0, 1));

// Dominant pitch sets a moving point of colour.
p = pitch();
d = abs(i/n - p);
v = clamp(1 - d*4, 0, 1) * (vu() + 0.1);
hsv(p * 0.83, 1, v);

// High frequencies trigger sparkles on random pixels.
phase = hash(i)*7;
flicker = wave(t*4 + phase);
level = treble();
v = pow(flicker, 8) * level * 4;
hsv(0.7 + hash(i)*0.15, 0.3, clamp(v, 0, 1));

// Continuous spectrum across the strip — no hard band edges.
x = i/n;
bIdx = x * 7;
b1 = floor(bIdx);
b2 = b1 + 1;
frac = bIdx - b1;
lev = mix(band(b1), band(b2), frac);
hsv(x * 0.83, 1, lev);
